    private static byte[] GenerateEmptyBlock()
    {
        byte[] data = new byte[BlockSize * BlockSize * BytesPerPixel];
        for (int i = 0; i < data.Length; i += 4)
        {
            data[i] = 64;     // B
            data[i + 1] = 37; // G
            data[i + 2] = 37; // R
            data[i + 3] = 255; // A
        }
        return data;
    }

    public static byte[]? GetBlockData(int blockType, string controlMode)
    {
        if (blockType == 0) return Empty;

		if (controlMode == "WORLD")
		{
			return blockType switch
			{
				0x02 => WBlock2, 	0x03 => WBlock3, 	0x04 => WBlock4,	0x05 => WBlock5,
				0x06 => WBlock6, 	0x07 => WBlock7,	0x08 => WBlock8, 	0x09 => WBlock9, 
				0x12 => GBlock2, 	0x13 => GBlock3, 	0x14 => GBlock4, 	0x15 => GBlock5,
				0x16 => GBlock6, 	0x17 => GBlock7, 	0x18 => GBlock8, 	0x19 => GBlock9,
				0x22 => WBlockIBM, 	0x23 => WBlockIBM, 	0x24 => WBlockIBM, 	0x25 => WBlockIBM,
				0x26 => WBlockIBM, 	0x27 => WBlockIBM, 	0x28 => WBlockIBM,	_ => Empty
			};
		}

        return blockType switch
        {
            0x02 => CBlock2, 	0x03 => CBlock3, 	0x04 => CBlock4, 	0x05 => CBlock5,
            0x06 => CBlock6, 	0x07 => CBlock7, 	0x08 => CBlock8, 	0x09 => CBlock9, 
            0x12 => GBlock2, 	0x13 => GBlock3, 	0x14 => GBlock4, 	0x15 => GBlock5,
            0x16 => GBlock6, 	0x17 => GBlock7, 	0x18 => GBlock8, 	0x19 => GBlock9,
			0x22 => CBlockIBM, 	0x23 => CBlockIBM, 	0x24 => CBlockIBM, 	0x25 => CBlockIBM,
			0x26 => CBlockIBM, 	0x27 => CBlockIBM, 	0x28 => CBlockIBM,	_ => Empty
        };
    }
